var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이것으로 행적 보고를 마치겠습니다.","JPN":"これにて足取りの報告を終わります。","ENG":"This concludes my report, sir.","TWN":"以上報告完畢。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"정말 충격적이군.","JPN":"本当に衝撃的だな。","ENG":"Shocking.","TWN":"真是令人震驚。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그렇게 우호적이던 제프티 바이오테크가 비인도적인 실험을 자행하던 집단인 데다가…….","JPN":"あんなに友好的だったジェフティ・バイオテックが、非人道的な実験を行っていた集団である上に……","ENG":"Who would've thought Jehuty Biotech would conduct such inhumane experiments...","TWN":"曾經那麼友好的傑夫堤生物科技，竟然是進行非人道實驗的集團，而且……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>형제들</color>이란 조직은 국가에 극히 위험한 자들이죠.","JPN":"<color=#ffd34c>兄弟</color>という組織は国家に極めて脅威になる者たちです。","ENG":"The organization called <color=#ffd34c>The Brothers Abandoned</color> pose a great danger to this country.","TWN":"<color=#ffd34c>兄弟們</color>這個組織對國家而言極其危險。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그러니 말일세. 그것들이 북방합의체와 결탁했다고 하면, 매국노 같은 합병파 놈들도 한동안은 수그러들겠지만.","JPN":"そのとおりだ。それが北方合意体と結託したとあれば、売国奴のような合併派のやつらもしばらくは大人しくなるだろうが。","ENG":"You're absolutely right. Although, if they were to collude with the Northern Union, those Northern Unionist scum would also lie low for a while.","TWN":"沒錯，若他們和北方和議會勾搭上，那統一派傢伙應該也會消沉一段陣子。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"……자네는 정말 그들이 침식체를 무기로 쓰려 한다고 믿나?","JPN":"……君は本当に彼らが侵食体を武器として使おうとしていると信じているのか？","ENG":"Do you really believe they are trying to weaponize C.O.s?","TWN":"……你真的相信他們要用侵蝕體做武器嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"의심의 여지는 희박합니다. 한나 엔더슨을 사칭한 자는 결국 그림자처럼 되어 저희를 공격했으니까요.","JPN":"ほとんど疑う余地はないかと。ハンナ・アンダーソンを騙った者は、結局シャドウとなり我々を攻撃したのですから。","ENG":"Hanna Anderson's impersonator eventually became a Shadow and attacked us, leaving little room for doubt.","TWN":"可信度蠻高的，因爲冒充漢娜·安德森的人後來就成為暗影，還攻擊我們。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그래. 자네가 제출한 자료는 확실히 받았네.","JPN":"わかった。君が提出した資料は確かに受け取った。","ENG":"Very well. I have received the documents you've submitted.","TWN":"嗯，我有收到你提交的資料。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 자네도 알다시피 한나 엔더슨은 평범한 인간이었어.","JPN":"だが、君も知ってのとおり、ハンナ・アンダーソンは普通の人間だったんだ。","ENG":"However, as you know, Hanna Anderson was a normal person.","TWN":"但是你也知道，漢娜·安德森只是個普通人。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"카운터도 아닌 사람이 그림자로 변하는 일은 전례가 없지 않나?","JPN":"カウンターでもない人間がシャドウとなることは前例がないだろう？","ENG":"Has there even been a case where a non-Counter turned into a Shadow?","TWN":"非制裁者的人變成暗影，這件事可說是史無前例吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그림자의 핵에 대해서도 파악하고 있던 자들입니다. 저희가 모르는 사실은 얼마든지 더 있을 수 있죠.","JPN":"シャドウの核についても把握していた者たちです。我々の知らない事実はいくらでもあると思います。","ENG":"They appear to be familiar with Shadows and their cores. Therefore, it is reasonable to assume that they know something we do not, sir.","TWN":"他們掌握暗影的核心，可能還有許多我們不知道的事情。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"임무에서 복귀하자마자 조사까지 맡아 줘서 고생 많았네. 래시포드 장교.","JPN":"任務から復帰するなり調査まで引き受けてくれてご苦労だったな。ラッシュフォード将校。","ENG":"Officer Rashford, I'm sorry to put you in charge of the investigation so soon after your return from your mission.","TWN":"才剛結束任務就著手調查，真是辛苦你了，雷斯福特軍官。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"제 성격 탓일 뿐입니다. 남에게 맡기면 기분이 편치 못해서요.","JPN":"私の性格上、人に任せると気が休まりませんので。","ENG":"Please, don't be. I wouldn't have felt comfortable leaving it to someone else.","TWN":"可能是因為我個性的緣故，交給別人處理不太放心。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그리고 일전에 얘기했던 자네에 대한 위원회의 왕실 최고 기술자 자격 검토안 말일세.","JPN":"あと、この前話した委員会の王室最高技術者の資格検討案なんだが……","ENG":"And about that Chief Technician position we talked about last time...","TWN":"還有，之前提過的，委員會對於你的皇室頂尖技師資格審查案。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"나도 찬성하기로 했네.","JPN":"私も賛成することにした。","ENG":"I have agreed to nominate you.","TWN":"我也決定贊成。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네? 애초의 목적이던 성유물의 회수에 실패했습니다만……?","JPN":"え？　当初の目的だった聖遺物の回収には失敗しておりますが……？","ENG":"I beg your pardon? But I failed to retrieve the Holy Relic...","TWN":"嗯？可是回收聖遺物任務失敗……？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"자네는 우리 나라의 잠재적인 위협을 밝혀내고 그림자를 요격했어.","JPN":"君は我が国の潜在的な脅威を暴き、シャドウを撃退した。","ENG":"Nevertheless, you have uncovered a potential threat to this country and defeated a Shadow.","TWN":"你發現我們國家的潛在危機，還成功阻止暗影。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};